<?php require __DIR__.'/../includes/bootstrap.php';$booth=booth_by_slug(trim($_GET['slug']??''));if(!$booth||($booth['status']!=='approved'&&!can_manage_booth($booth))){http_response_code(404);exit('Booth not found.');}if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();if(($_POST['action']??'')==='add_cart'){cart_add((int)$_POST['product_id'],(int)($_POST['quantity']??1));flash('success','Added to your cart.');redirect_route('booth/view.php',['slug'=>$booth['slug']]);}}if(booth_management_ready())record_booth_view((int)$booth['id']);$gallery=[];$downloads=[];$team=[];if(booth_management_ready()){$q=db()->prepare('SELECT * FROM booth_gallery WHERE booth_id=? ORDER BY sort_order,created_at');$q->execute([$booth['id']]);$gallery=$q->fetchAll();$q=db()->prepare('SELECT * FROM booth_downloads WHERE booth_id=? AND is_public=1 ORDER BY created_at DESC');$q->execute([$booth['id']]);$downloads=$q->fetchAll();$q=db()->prepare("SELECT tm.role,u.display_name FROM booth_team_members tm JOIN users u ON u.id=tm.user_id WHERE tm.booth_id=? AND tm.status='active' ORDER BY tm.role,u.display_name");$q->execute([$booth['id']]);$team=$q->fetchAll();}$ps=db()->prepare("SELECT * FROM booth_products WHERE booth_id=? AND status='active' ORDER BY is_featured DESC,created_at DESC");$ps->execute([$booth['id']]);$products=$ps->fetchAll();$us=db()->prepare('SELECT u.* FROM universes u JOIN booth_universes bu ON bu.universe_id=u.id WHERE bu.booth_id=? ORDER BY u.name');$us->execute([$booth['id']]);$universes=$us->fetchAll();app_header($booth['name']);?>
<section class="booth-profile-hero" <?php if($booth['banner_path']):?>style="background-image:linear-gradient(90deg,rgba(7,8,18,.94),rgba(7,8,18,.45)),url('<?=e(base_url($booth['banner_path']))?>')"<?php endif?>><?php if($booth['logo_path']):?><img class="booth-profile-logo" src="<?=e(base_url($booth['logo_path']))?>" alt=""><?php endif?><div><p class="eyebrow">VIRTUAL CONVENTION BOOTH</p><h1><?=e($booth['name'])?></h1><p class="lead"><?=e($booth['tagline'])?></p><p>Hosted by <?=e($booth['owner_name'])?><?php if($booth['brand_name']):?> · <a href="../brand/view.php?slug=<?=urlencode($booth['brand_slug'])?>"><?=e($booth['brand_name'])?></a><?php elseif($booth['company_name']):?> · <a href="../company/view.php?slug=<?=urlencode($booth['company_slug'])?>"><?=e($booth['company_name'])?></a><?php endif?></p><div><?php foreach($universes as $x):?><a class="pill" href="../universe/view.php?slug=<?=urlencode($x['slug'])?>"><?=e($x['name'])?></a><?php endforeach?></div></div><div class="booth-hero-actions"><a class="button ghost" href="../cart.php">Cart (<?=cart_count()?>)</a><?php if($booth['website']):?><a class="button secondary" target="_blank" rel="noopener" href="<?=e($booth['website'])?>">Visit Website</a><?php endif?></div></section>
<section class="booth-public-layout"><main><section class="app-card booth-about"><h2>About This Booth</h2><p><?=nl2br(e($booth['description']))?></p></section><section><div class="section-heading"><div><p class="eyebrow">SHOP THE TABLE</p><h2>Products & Convention Specials</h2></div></div><div class="product-store-grid"><?php foreach($products as $p):?><article class="store-product-card"><a class="store-product-image-link" href="product.php?slug=<?=urlencode($p['slug'])?>"><?php if($p['image_path']):?><img src="<?=e(base_url($p['image_path']))?>" alt="<?=e($p['name'])?>"><?php else:?><div class="product-placeholder">GNM</div><?php endif?></a><div class="store-product-body"><div class="product-tags"><?php if($p['convention_exclusive']):?><span>Convention Exclusive</span><?php endif?><?php if($p['signed_item']):?><span>Signed</span><?php endif?><?php if($p['preorder']):?><span>Preorder</span><?php endif?></div><h3><a href="product.php?slug=<?=urlencode($p['slug'])?>"><?=e($p['name'])?></a></h3><p><?=e(mb_strimwidth((string)$p['description'],0,150,'…'))?></p><div class="product-price">$<?=number_format((float)$p['price'],2)?><?php if($p['compare_at_price']):?> <del>$<?=number_format((float)$p['compare_at_price'],2)?></del><?php endif?></div><?php if($booth['commerce_mode']==='demo'):?><form method="post" class="add-cart-form"><?=csrf_field()?><input type="hidden" name="action" value="add_cart"><input type="hidden" name="product_id" value="<?=$p['id']?>"><input type="number" name="quantity" value="1" min="1" max="99"><button class="button primary">Add to Cart</button></form><?php elseif($booth['commerce_mode']==='external'&&$booth['external_store_url']):?><a class="button primary" target="_blank" rel="noopener" href="<?=e($booth['external_store_url'])?>">Buy from Seller</a><?php else:?><span class="muted">Display only</span><?php endif?></div></article><?php endforeach?><?php if(!$products):?><div class="empty-state"><h3>The table is being stocked.</h3><p>Check back for products and convention specials.</p></div><?php endif?></div></section><?php if($gallery):?><section class="app-card"><h2>Booth Gallery</h2><div class="public-booth-gallery"><?php foreach($gallery as $g):?><figure><img src="<?=e(base_url($g['image_path']))?>" alt="<?=e($g['caption'])?>"><figcaption><?=e($g['caption'])?></figcaption></figure><?php endforeach?></div></section><?php endif?><?php if($downloads):?><section class="app-card"><h2>Downloads & Resources</h2><div class="download-list"><?php foreach($downloads as $d):$href=$d['file_path']?base_url($d['file_path']):$d['external_url'];?><a target="_blank" rel="noopener" href="<?=e($href)?>"><strong><?=e($d['title'])?></strong><span><?=e($d['description'])?></span></a><?php endforeach?></div></section><?php endif?></main><aside><section class="app-card"><h2>Booth Information</h2><dl><dt>Contact</dt><dd><a href="mailto:<?=e($booth['contact_email'])?>"><?=e($booth['contact_email'])?></a></dd><?php if(booth_management_ready()):?><dt>Status</dt><dd><?=e(ucfirst($booth['booth_presence']??'offline'))?></dd><?php if(!empty($booth['location_label'])):?><dt>Location</dt><dd><?=e($booth['location_label'])?></dd><?php endif?><?php if(!empty($booth['hours_text'])):?><dt>Hours</dt><dd><?=nl2br(e($booth['hours_text']))?></dd><?php endif?><?php endif?><dt>Checkout</dt><dd><?=e($booth['commerce_mode']==='demo'?'Demo mode—no live payment':'Seller-managed')?></dd></dl><?php if(booth_management_ready()):?><div class="booth-socials"><?php foreach(['instagram_url'=>'Instagram','youtube_url'=>'YouTube','tiktok_url'=>'TikTok','discord_url'=>'Discord'] as $f=>$label):if(!empty($booth[$f])):?><a target="_blank" rel="noopener" href="<?=e($booth[$f])?>"><?=e($label)?></a><?php endif;endforeach?></div><?php endif?></section><?php if($team):?><section class="app-card"><h2>Booth Team</h2><?php foreach($team as $m):?><div class="manage-list-item"><strong><?=e($m['display_name'])?></strong><span><?=e(ucfirst($m['role']))?></span></div><?php endforeach?></section><?php endif?><?php if(booth_management_ready()&&(!empty($booth['shipping_policy'])||!empty($booth['return_policy']))):?><section class="app-card"><h2>Shop Policies</h2><?php if(!empty($booth['shipping_policy'])):?><h3>Shipping</h3><p><?=nl2br(e($booth['shipping_policy']))?></p><?php endif?><?php if(!empty($booth['return_policy'])):?><h3>Returns</h3><p><?=nl2br(e($booth['return_policy']))?></p><?php endif?></section><?php endif?><section class="app-card demo-notice"><strong>Class Demo Commerce</strong><p>The storefront, cart, checkout, inventory, and orders are functional. No card is charged until a live provider is connected.</p></section></aside></section><?php app_footer();